  ('9e2ebf00-92b3-40a7-b0f8-30e257b63bfd', 'KIMCHI-645', 'Large Tamago Pan 26.5 x 19.5 cm Glitter', 'Rectangular pan for tamagoyaki, perfect for frying layered omelets.', 'Large Tamago Pan 26.5 x 19.5 cm Glitter', 'Rectangular pan for tamagoyaki, perfect for frying layered omelets.'),
  ('494357c3-c27d-40e6-80eb-081a5390f959', 'KIMCHI-644', 'Small Tamago Pan 23.5 x 17.5 cm Glitter', 'Rectangular pan for tamagoyaki, perfect for frying layered omelets.', 'Small Tamago Pan 23.5 x 17.5 cm Glitter', 'Rectangular pan for tamagoyaki, perfect for frying layered omelets.'),
